        {[4,5].map(x => [19,20].map(y => <P key={`ll${x}${y}`} x={x} y={y} c={'#4a3728'} />))}
        {[9,10].map(x => [19,20].map(y => <P key={`rl${x}${y}`} x={x} y={y} c={'#4a3728'} />))}
        {[4,5,9,10].map(x => <P key={`lbo${x}`} x={x} y={18} c={outline} />)}
      </svg>
    </div>
  );
};

// ─── Small pixel preview icon ─────────────────────────────────────────────────
const PixelIcon = ({ item, category, hairCol }) => {
  if (category === 'skin' || category === 'hairColor') {
    return <div style={{ width: 36, height: 36, borderRadius: '50%', background: item.color, boxShadow: 'inset 0 -2px 4px rgba(0,0,0,0.2)' }} />;
  }
  if (category === 'pets') return <span style={{ fontSize: '1.8rem' }}>{item.emoji}</span>;
  if (category === 'hairStyle' && item.pixels) {
    return (
      <svg viewBox="-2 -4 20 14" width="44" height="32" style={{ imageRendering: 'pixelated' }}>
        {item.pixels.map((px, i) => (
          <rect key={i} x={px[0]-3} y={px[1]+1} width={1} height={1}
            fill={px[2] === 'h' ? hairCol : px[2]} />
        ))}
      </svg>
    );
  }
  if (category === 'animalEars' && item.pixels) {
    return (
      <svg viewBox="2 -3 12 8" width="44" height="28" style={{ imageRendering: 'pixelated' }}>
        {item.pixels.map((px, i) => (
          <rect key={i} x={px[0]} y={px[1]} width={1} height={1} fill={px[2]} />
        ))}
      </svg>
    );
  }
  if (category === 'armour' && item.pixels) {
    return (
      <svg viewBox="3 44 10 10" width="40" height="40" style={{ imageRendering: 'pixelated' }}>
        {item.pixels.map((px, i) => (
          <rect key={i} x={px[0]} y={px[1]} width={1} height={1} fill={px[2]} />
        ))}
      </svg>
    );
  }
  return <div style={{ width: 36, height: 36, borderRadius: '50%', background: item.color || '#ccc' }} />;
};

