  const [saved,       setSaved]       = useState(false);
  const [selections,  setSelections]  = useState({
    skin:       's1',
    hairStyle:  'hs1',
    hairColor:  'hc2',
    animalEars: null,
    armour:     'ar1',
    pets:       null,
  });

  const handleSelect = (key, id) => {
    setSelections(p => ({ ...p, [key]: id }));
    setActiveModal(null);
  };

  return (
    <div className="page-container">
      <div className="avatar-page-layout">

        {/* Avatar Preview */}
        <div className="card avatar-preview-card" data-testid="avatar-main">
          <h2 className="section-title">Your Avatar</h2>
          <div className="avatar-display">
            <PixelAvatar
              skin={SHOP.skin.find(i => i.id === selections.skin)}
              hairStyle={SHOP.hairStyle.find(i => i.id === selections.hairStyle)}
              hairColor={SHOP.hairColor.find(i => i.id === selections.hairColor)}
              animalEars={SHOP.animalEars.find(i => i.id === selections.animalEars)}
              armour={SHOP.armour.find(i => i.id === selections.armour)}
              pet={SHOP.pets.find(i => i.id === selections.pets)}
            />
            <input
              type="text"
              placeholder="Enter your Avatar name......"
              value={avatarName}
              onChange={e => { setAvatarName(e.target.value); setSaved(false); }}
              className="avatar-name-input"
              data-testid="avatar-name-input"
            />
            <button className="create-button" onClick={() => setSaved(true)}
              data-testid="avatar-create-btn">
              CREATE AVATAR
            </button>
            {saved && avatarName && (
              <div className="avatar-saved-badge">✅ {avatarName} saved!</div>
            )}
          </div>
        </div>

        {/* Category Cards */}
        <div className="categories-panel">
          {CATEGORIES.map(cat => (
            <CategoryCard key={cat.key} cat={cat}
              selections={selections} onMore={setActiveModal} />
          ))}
        </div>
      </div>

      {activeModal && (
        <ShopModal
          category={activeModal}
          selections={selections}
          onSelect={id => handleSelect(activeModal.key, id)}
          onClose={() => setActiveModal(null)}
        />
      )}
    </div>
  );
};

export default ProgramAvatar;
